/* Minified JavaScript Bundle */
document.addEventListener('DOMContentLoaded',()=>{const video=document.getElementById('howItWorksVideo');const playButton=document.getElementById('playButton');if(playButton&&video){playButton.addEventListener('click',()=>{if(video.paused){video.play();playButton.style.opacity='0';playButton.style.pointerEvents='none';video.setAttribute('controls','true')}});video.addEventListener('play',()=>{playButton.style.opacity='0';playButton.style.pointerEvents='none';video.setAttribute('controls','true')});video.addEventListener('pause',()=>{playButton.style.opacity='1';playButton.style.pointerEvents='auto';video.removeAttribute('controls')})}});document.querySelectorAll('.faq-question').forEach(button=>{button.addEventListener('click',()=>{const expanded=button.getAttribute('aria-expanded')==='true';button.setAttribute('aria-expanded',!expanded);const answer=button.nextElementSibling;if(!expanded){answer.hidden=false}else{answer.hidden=true}})});